const _ = require('lodash');

class ProblemsService {
  constructor(problemRepository) {
    this.problemRepository = problemRepository;
  }

  async listProblems({ limit, difficulty, tags, includeComponents }) {
    // Fetch all problems from repository
    let problems = await this.problemRepository.getAllProblems();

    // Apply filters
    if (difficulty) {
      problems = problems.filter(p => p.difficulty === difficulty);
    }
    if (tags && tags.length > 0) {
      problems = problems.filter(p => tags.every(t => p.tags.includes(t)));
    }

    // Apply limit
    if (limit) {
      problems = problems.slice(0, limit);
    }

    // Prepare metadata
    const metadata = {};

    if (includeComponents) {
      // Compute componentLanguageTotals and componentStatusTotals for filtered+limited problems
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      for (const problem of problems) {
        if (!problem.components) continue;
        for (const comp of problem.components) {
          // Language totals
          if (comp.language) {
            componentLanguageTotals[comp.language] = (componentLanguageTotals[comp.language] || 0) + 1;
          }
          // Status totals
          if (comp.status) {
            componentStatusTotals[comp.status] = (componentStatusTotals[comp.status] || 0) + 1;
          }
        }
      }

      metadata.componentLanguageTotals = componentLanguageTotals;
      metadata.componentStatusTotals = componentStatusTotals;
    }

    return { problems, metadata };
  }
}

module.exports = ProblemsService;
